# ---------------------------------------------------------------------------
# BUG-H1: json_has_key matches keys inside string values (false positive)
#
# The bug: json_has_key uses `grep -q "\"key\""` without requiring a colon.
# A JSON file where "id" appears only inside a string value returns true.
# [BUG from quality/code_reviews/pass1_structural.md, line 7]
# Skip guard: set BUG_SKIP_H1=0 to enable
# Fix: quality/patches/BUG-H1-fix.patch
# ---------------------------------------------------------------------------
test_BUG_H1_json_has_key_false_positive() {
    if [ "${BUG_SKIP_H1:-1}" = "1" ]; then
        echo "  SKIP: BUG-H1 skip guard active (set BUG_SKIP_H1=0 to run red phase)"
        SKIP=$((SKIP + 1))
        return 0
    fi

    # Create a JSON file where "id" appears only as a STRING VALUE, NOT as a key.
    # The bug: json_has_key "id" matches any occurrence of "id" in the file,
    # including when "id" is a VALUE (e.g., "field_type": "id").
    # This causes false-positive key detection — the gate thinks "id" is present
    # as a key when it is only a value in a different field.
    local tmpfile
    tmpfile=$(mktemp /tmp/bug_h1_test.XXXXXX.json)
    cat > "$tmpfile" <<'EOF'
{
  "field_type": "id",
  "schema_version": "1.1",
  "project": "quality-playbook"
}
EOF
    # Note: "id" appears as a VALUE ("id") not as a key ("id": ...).
    # json_has_key "id" should return false (exit 1) — "id" is not a JSON key here.
    # Buggy behavior: grep -q "\"id\"" matches the VALUE "id" and returns true.

    # Reproduce the buggy json_has_key from quality_gate.sh:75-78
    json_has_key_buggy() {
        local file="$1" key="$2"
        grep -q "\"${key}\"" "$file" 2>/dev/null
    }

    # Expected: json_has_key "id" should return false (1) — "id" is not a key here
    # Bug behavior: returns true (0) because "id" appears inside the string value
    local result=0
    if json_has_key_buggy "$tmpfile" "id"; then
        echo "  BUG CONFIRMED: json_has_key returned true for 'id' appearing only in string value"
        echo "  JSON content: $(cat "$tmpfile")"
        result=1
    else
        echo "  BUG FIXED: json_has_key correctly returned false for 'id' in string value only"
    fi

    rm -f "$tmpfile"
    return $result
}

