    if grep -qE 'if ls \$\{q\}/test_functional\.' "$gate"; then
        echo "  BUG CONFIRMED: quality_gate.sh:124 uses ls-glob for functional test existence (nullglob vulnerable)"
        return 1  # FAILS on unpatched code (red phase)
    elif grep -qE 'find.*test_functional.*print.*quit.*grep -q' "$gate" || \
         grep -n 'test_functional' "$gate" | grep -q 'find'; then
        echo "  BUG FIXED: quality_gate.sh now uses find-based functional test existence check"
        return 0
    else
        echo "  INDETERMINATE: cannot confirm presence of ls-glob or find-based check at line 124"
        return 2
    fi
}

