        has_cross_val=1
    fi
    if [ "$has_cross_val" -eq 0 ]; then
        echo "  BUG CONFIRMED: no cross-validation between tdd-results.json phase values and log tags"
        echo "  SKILL.md:1589 mandates: if red_phase='pass' in JSON, BUG-NNN.red.log first line must be RED"
        echo "  Gate validates field presence (lines 239-248) and tag format (lines 322-325) independently"
        echo "  But never compares them — contradiction between JSON and log goes undetected"
        return 1  # FAILS on unpatched code (red phase)
    else
        echo "  BUG FIXED: cross-validation between sidecar JSON phase values and log tags is present"
        return 0
    fi
}

