        echo "  Phase 2 entry gate (lines 890-940): no 120-line minimum check found"
        echo "  After BUG-M3 fix: thin EXPLORATION.md (~15 lines) still passes Phase 2 entry gate"
        return 1  # FAILS on unpatched code (red phase)
    elif [ -n "$phase2_120_check" ]; then
        echo "  BUG FIXED: Phase 2 entry gate now includes 120-line check: $phase2_120_check"
        return 0
    else
        echo "  INCONCLUSIVE: Phase 1 check #1 (120-line) not found at expected location"
        return 1
    fi
}

